import React from "react";
import HomeScreen from "./HomeScreen";
import GoalsScreen from "./GoalsScreen";
import LoansScreen from "./LoansScreen";
import ProfileScreen from "./ProfileScreen";

export default function Dashboard({ currentTab, ...props }) {
  const renderScreen = () => {
    switch (currentTab) {
      case "Home": return <HomeScreen {...props} />;
      case "Goals": return <GoalsScreen {...props} />;
      case "Loans": return <LoansScreen {...props} />;
      case "Profile": return <ProfileScreen {...props} />;
      default: return <HomeScreen {...props} />;
    }
  };

  return (
    <div className="w-screen h-screen flex flex-col bg-gray-50">
      <div className="flex-1 overflow-auto">{renderScreen()}</div>
      {/* Bottom Navigation */}
      <nav className="flex justify-around items-center bg-white border-t border-gray-200 py-3">
        {["Home", "Goals", "Loans", "Profile"].map((tab) => (
          <button key={tab} className="text-gray-500 hover:text-teal-600">
            {tab}
          </button>
        ))}
      </nav>
    </div>
  );
}
